#### 📝 **具体改进内容**：

**1. 增强 CORS 配置函数**
```typescript
// 新增文件：src/dashboard/middleware/cors.ts
import { FastifyRequest } from 'fastify';

/**
 * CORS 源验证器
 * 支持字符串、数组、正则表达式、函数
 */
export const corsConfig = {
  origin: (origin: string | undefined, callback: any) => {
    const allowedOrigins = getAllowedOrigins();

    // 允许无 origin 的请求（如移动应用、Postman）
    if (!origin) return callback(null, true);

    // 检查是否在允许列表中
    if (allowedOrigins.some(allowed => checkOrigin(origin, allowed))) {
      return callback(null, true);
    }

    // 记录未授权的访问尝试
    console.warn(`[CORS] Blocked unauthorized origin: ${origin}`);
    callback(new Error('Not allowed by CORS'));
  },
  credentials: true,
  exposedHeaders: ['Content-Range', 'X-Content-Range'],
  maxAge: 86400 // 24小时预检缓存
};

/**
 * 获取允许的源列表（根据环境）
 */
function getAllowedOrigins(): (string | RegExp)[] {
  const env = process.env.NODE_ENV || 'development';

  if (env === 'production') {
    // 生产环境：严格白名单
    const prodOrigins = process.env.CORS_ALLOW_ORIGINS?.split(',') || [];
    return prodOrigins.map(o => new RegExp(`^${o.replace(/\*/g, '.*')}$`));
  }

  // 开发环境：允许本地端口
  return [
    /^http:\/\/localhost:\d+$/,
    /^http:\/\/127\.0\.0\.1:\d+$/,
    /^http:\/\/\[::1\]:\d+$/
  ];
}

/**
 * 检查 origin 是否匹配允许的模式
 */
function checkOrigin(origin: string, allowed: string | RegExp): boolean {
  if (allowed instanceof RegExp) {
    return allowed.test(origin);
  }
  return origin === allowed;
}
```

**2. 添加安全头中间件**
```typescript
// 新增文件：src/dashboard/middleware/security-headers.ts
import { FastifyInstance } from 'fastify';

/**
 * 安全响应头配置
 * 防止 XSS、点击劫持、MIME 嗅探等攻击
 */
export async function registerSecurityHeaders(server: FastifyInstance) {
  server.addHook('onSend', async (request, reply, payload) => {
    // 内容安全策略（CSP）
    reply.header('Content-Security-Policy', 
      "default-src 'self'; " +
      "script-src 'self' 'unsafe-inline' 'unsafe-eval'; " +
      "style-src 'self' 'unsafe-inline'; " +
      "img-src 'self' data: https:; " +
      "connect-src 'self' ws://localhost:* ws://127.0.0.1:*; " +
      "frame-ancestors 'none'"
    );

    // 防止点击劫持
    reply.header('X-Frame-Options', 'DENY');

    // 防止 MIME 嗅探
    reply.header('X-Content-Type-Options', 'nosniff');

    // XSS 防护
    reply.header('X-XSS-Protection', '1; mode=block');

    // Referrer 策略
    reply.header('Referrer-Policy', 'strict-origin-when-cross-origin');

    // 权限策略（替代 Feature-Policy）
    reply.header('Permissions-Policy', 
      'geolocation=(), ' +
      'microphone=(), ' +
      'camera=(), ' +
      'payment=()'
    );

    return payload;
  });
}
```

