/**
 * 加密配置管理器
 * 负责从加密存储中读取敏感配置
 */
import fs from 'fs';
import path from 'path';
import { EncryptionUtil } from '../utils/encryption';

interface EncryptedConfig {
  anthropicAuthToken?: string;
  anthropicBaseUrl?: string;
  [key: string]: string | undefined;
}

export class EncryptedConfigManager {
  private static readonly CONFIG_FILE = '.env.encrypted';

  /**
   * 加密并保存配置
   */
  static saveEncryptedConfig(config: EncryptedConfig): void {
    const encrypted: Record<string, string> = {};

    for (const [key, value] of Object.entries(config)) {
      if (value) {
        encrypted[key] = EncryptionUtil.encrypt(value);
      }
    }

    const configPath = path.join(process.cwd(), this.CONFIG_FILE);
    fs.writeFileSync(
      configPath,
      JSON.stringify(encrypted, null, 2),
      { mode: 0o600 } // 只有所有者可读写
    );
  }

  /**
   * 读取并解密配置
   */
  static loadEncryptedConfig(): Partial<EncryptedConfig> {
    const configPath = path.join(process.cwd(), this.CONFIG_FILE);

    if (!fs.existsSync(configPath)) {
      return {};
    }

    const encrypted = JSON.parse(fs.readFileSync(configPath, 'utf8'));
    const decrypted: Partial<EncryptedConfig> = {};

    for (const [key, value] of Object.entries(encrypted)) {
      try {
        decrypted[key] = EncryptionUtil.decrypt(value as string);
      } catch (error) {
        console.warn(`Failed to decrypt ${key}, using environment variable as fallback`);
      }
    }

    return decrypted;
  }

  /**
   * 获取 Anthropic API Token（优先从加密配置读取）
   */
  static getAnthropicToken(): string {
    const encrypted = this.loadEncryptedConfig();
    return encrypted.anthropicAuthToken || process.env.ANTHROPIC_AUTH_TOKEN || '';
  }
}
